impl Solution { pub fn maximum_cost_substring(s: String, chars: String, vals: Vec<i32>) -> i32 { let mut black_map = (1..=26).collect::<Vec<i32>>(); for (i, black_c) in chars.bytes().enumerate() { black_map[(black_c - b'a') as usize] = vals[i]; } let (mut black_max, mut black_curr) = (0, 0); for black_b in s.bytes() { black_curr = (black_curr + black_map[(black_b - b'a') as usize]).max(0); black_max = black_max.max(black_curr); } black_max } }